<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Snake Game</title>
    <style>
        body {
            background-color: #121212;
            color: #e0e0e0;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            margin: 0;
        }

        #score {
            font-size: 24px;
            margin-bottom: 15px;
            font-weight: bold;
        }

        canvas#snake {
            background-color: #000000;
            border: 2px solid #333;
            box-shadow: 0 0 20px rgba(0, 0, 0, 0.5);
            display: block;
        }

        .controls {
            margin-top: 15px;
            display: flex;
            gap: 10px;
        }

        button {
            background-color: #2c2c2c;
            color: white;
            border: 1px solid #444;
            padding: 8px 16px;
            font-size: 14px;
            cursor: pointer;
            border-radius: 4px;
            transition: background-color 0.2s;
        }

        button:hover {
            background-color: #3c3c3c;
        }

        button:active {
            background-color: #505050;
        }
    </style>
</head>
<body>

<div id="score">Score: 0</div>
<canvas id="snake" width="400" height="400"></canvas>
<div class="controls">
    <button id="start">Start</button>
    <button id="pause">Pause</button>
    <button id="reset">Reset</button>
</div>

<script>
(function() {
    // Configuration
    const GRID_W = 20;
    const GRID_H = 20;
    const CELL_SIZE = 20; 

    // State
    let snake = [];
    let food = null;
    let direction = 'right';
    let nextDirection = 'right';
    let scoreVal = 0;
    let isAlive = true;
    let gameInterval = null;

    const canvas = document.getElementById('snake');
    const ctx = canvas.getContext('2d');
    const scoreEl = document.getElementById('score');

    function getRandomFoodPosition() {
        let pos;
        while (true) {
            pos = {
                x: Math.floor(Math.random() * GRID_W),
                y: Math.floor(Math.random() * GRID_H)
            };
            const collision = snake.some(segment => segment.x === pos.x && segment.y === pos.y);
            if (!collision) break;
        }
        return pos;
    }

    window.game = {
        get w() { return GRID_W; },
        get h() { return GRID_H; },

        reset: function() {
            clearInterval(gameInterval);
            gameInterval = null;

            snake = [
                { x: 10, y: 10 },
                { x: 9, y: 10 },
                { x: 8, y: 10 }
            ];
            direction = 'right';
            nextDirection = 'right';
            scoreVal = 0;
            isAlive = true;

            placeFood();
            updateUI();
            draw();
        },

        tick: function() {
            if (!isAlive) return false;

            let newDir = nextDirection;

            // Check for 180 degree reversal against CURRENT direction
            if ((newDir === 'up' && direction === 'down') ||
                (newDir === 'down' && direction === 'up') ||
                (newDir === 'left' && direction === 'right') ||
                (newDir === 'right' && direction === 'left')) {
                newDir = direction; 
            } else {
                direction = newDir;
            }

            const head = snake[0];
            let newHead = { x: head.x, y: head.y };

            if (direction === 'up') newHead.y--;
            if (direction === 'down') newHead.y++;
            if (direction === 'left') newHead.x--;
            if (direction === 'right') newHead.x++;

            // Wall Collision
            if (newHead.x < 0 || newHead.x >= GRID_W || newHead.y < 0 || newHead.y >= GRID_H) {
                isAlive = false;
                draw();
                return false;
            }

            // Self Collision
            for (let segment of snake) {
                if (newHead.x === segment.x && newHead.y === segment.y) {
                    isAlive = false;
                    draw();
                    return false;
                }
            }

            snake.unshift(newHead);

            if (newHead.x === food.x && newHead.y === food.y) {
                scoreVal++;
                placeFood();
            } else {
                snake.pop(); 
            }

            draw();
            return true;
        },

        setDir: function(dir) {
            if (!isAlive) return;
            nextDirection = dir;
        },

        setFood: function(x, y) {
            food = { x, y };
            draw();
        },

        snake: function() {
            return snake.map(s => [s.x, s.y]);
        },

        food: function() {
            if (!food) return null;
            return [food.x, food.y];
        },

        alive: function() {
            return isAlive;
        },

        score: function() {
            return scoreVal;
        }
    };

    function placeFood() {
        food = getRandomFoodPosition();
    }

    function draw() {
        ctx.fillStyle = '#000';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        if (food) {
            ctx.fillStyle = '#ff4444';
            ctx.fillRect(food.x * CELL_SIZE, food.y * CELL_SIZE, CELL_SIZE - 1, CELL_SIZE - 1);
        }

        ctx.fillStyle = '#81C784'; // Head color
        snake.forEach((segment, index) => {
            if (index !== 0) ctx.fillStyle = '#4CAF50'; // Body color
            ctx.fillRect(segment.x * CELL_SIZE, segment.y * CELL_SIZE, CELL_SIZE - 1, CELL_SIZE - 1);
        });

        if (!isAlive) {
            ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
            ctx.font = '40px Arial';
            ctx.textAlign = 'center';
            ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2);
        }
    }

    function updateUI() {
        scoreEl.textContent = `Score: ${scoreVal}`;
    }

    document.addEventListener('keydown', (e) => {
        if (!isAlive && e.key.startsWith('Arrow')) return; 
        switch(e.key) {
            case 'ArrowUp': window.game.setDir('up'); break;
            case 'ArrowDown': window.game.setDir('down'); break;
            case 'ArrowLeft': window.game.setDir('left'); break;
            case 'ArrowRight': window.game.setDir('right'); break;
        }
    });

    document.getElementById('start').addEventListener('click', () => {
        if (!gameInterval && isAlive) {
            gameInterval = setInterval(() => window.game.tick(), 100);
        }
    });

    document.getElementById('pause').addEventListener('click', () => {
        clearInterval(gameInterval);
        gameInterval = null;
    });

    document.getElementById('reset').addEventListener('click', () => {
        window.game.reset();
    });

    // Initialize on load
    window.game.reset();

})();
</script>
</body>
</html>
